/// Player spawn — pièce de départ, cellule (3,3) confirmée floor.
pub const PLAYER_START_X:     f32 = 3.5;
pub const PLAYER_START_Y:     f32 = 3.5;
pub const PLAYER_START_ANGLE: f32 = 0.0;   // face Est

/// Wall colour for tile index. N/S faces darkened for depth cue.
pub fn wall_color(tile_idx: u8, north_south: bool) -> (u8, u8, u8) {
    let (r, g, b) = match tile_idx % 8 {
        0 => (0xAA, 0x55, 0x22),
        1 => (0xCC, 0x99, 0x44),
        2 => (0x99, 0x44, 0x22),
        3 => (0xDD, 0xBB, 0x66),
        4 => (0x66, 0x44, 0x22),
        5 => (0x88, 0x88, 0x88),
        6 => (0xCC, 0x44, 0x44),
        _ => (0x44, 0x88, 0xCC),
    };
    if north_south {
        ((r as u32 * 7 / 10) as u8,
         (g as u32 * 7 / 10) as u8,
         (b as u32 * 7 / 10) as u8)
    } else {
        (r, g, b)
    }
}
